		require.NoError(t, err)

		req := httptest.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewReader(body))
		req = req.WithContext(context.Background())

		result := api.silencesBulk(req)
		require.NotNil(t, result.err)
		require.Equal(t, errorBadData, result.err.typ)

		errData, ok := result.data.(BulkSilenceError)
		require.True(t, ok)
		require.Equal(t, 1, errData.Index) // Error at index 1
	})

