		require.NoError(t, err)

		req := httptest.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewReader(body))
		req = req.WithContext(context.Background())

		result := api.silencesBulk(req)
		require.NotNil(t, result.err)
		require.Equal(t, errorBadData, result.err.typ)

		errData, ok := result.data.(BulkSilenceError)
		require.True(t, ok)
		require.Equal(t, 0, errData.Index)
		require.Contains(t, errData.Message, "createdBy")
	})

	// Test invalid time range (endsAt before startsAt)
	t.Run("validation_failure_invalid_time_range", func(t *testing.T) {
		api := &API{
			ready: func(f http.HandlerFunc) http.HandlerFunc { return f },
		}

		now := time.Now()
		startsAt := now.Add(2 * time.Hour)
		endsAt := now.Add(1 * time.Hour) // Before startsAt

		bulkReq := BulkSilenceRequest{
			Silences: []SilenceRequest{
				{
					Matchers: []SilenceMatcher{
						{Name: "alertname", Value: "TestAlert", IsRegex: false},
					},
					StartsAt:  &startsAt,
					EndsAt:    &endsAt,
					CreatedBy: "test_user",
					Comment:   "Invalid time range",
				},
			},
		}

		body, err := json.Marshal(bulkReq)
		require.NoError(t, err)

		req := httptest.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewReader(body))
		req = req.WithContext(context.Background())

		result := api.silencesBulk(req)
		require.NotNil(t, result.err)
		require.Equal(t, errorBadData, result.err.typ)

		errData, ok := result.data.(BulkSilenceError)
		require.True(t, ok)
		require.Equal(t, 0, errData.Index)
		require.Contains(t, errData.Message, "endsAt")
	})

	// Test invalid JSON body
	t.Run("invalid_json_body", func(t *testing.T) {
		api := &API{
			ready: func(f http.HandlerFunc) http.HandlerFunc { return f },
		}

		body := []byte("invalid json")
		req := httptest.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewReader(body))
		req = req.WithContext(context.Background())

		result := api.silencesBulk(req)
		require.NotNil(t, result.err)
		require.Equal(t, errorBadData, result.err.typ)
	})
}

func TestBulkSilenceIntegration(t *testing.T) {
	// Test with actual HTTP handler
	t.Run("http_handler", func(t *testing.T) {
		api := &API{
			ready: func(f http.HandlerFunc) http.HandlerFunc { return f },
		}

		bulkReq := BulkSilenceRequest{
			Silences: []SilenceRequest{
				{
					Matchers: []SilenceMatcher{
						{Name: "instance", Value: "localhost:9090", IsRegex: false},
						{Name: "job", Value: "prometheus", IsRegex: false},
					},
					CreatedBy: "operator",
					Comment:   "Silence for maintenance",
				},
			},
		}

		body, err := json.Marshal(bulkReq)
		require.NoError(t, err)

		// Create request
		req := httptest.NewRequest("POST", "/api/v1/silences/bulk", bytes.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		req = req.WithContext(context.Background())

		// Create handler through the wrapper
		wrap := func(f func(r *http.Request) apiFuncResult) http.HandlerFunc {
			return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
				result := f(r)
				if result.err != nil {
					fmt.Fprintf(w, `{"status":"error","error":"%s"}`, result.err.Error())
					return
				}
				w.Header().Set("Content-Type", "application/json")
				json.NewEncoder(w).Encode(result.data)
			})
		}

		handler := wrap(api.silencesBulk)
		recorder := httptest.NewRecorder()
		handler.ServeHTTP(recorder, req)

		require.Equal(t, http.StatusOK, recorder.Code)

		var respBody BulkSilenceResponse
		err = json.NewDecoder(recorder.Body).Decode(&respBody)
		require.NoError(t, err)
		require.Len(t, respBody.IDs, 1)
	})
}

